mutation AddReview($review: dctor_review_insert_input = {}) {
  review: insert_dctor_review_one(object: $review) {
      id: uuid
  }
}

query DoctorReviewQuery($where: dctor_review_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  reviews: dctor_review(where: $where, limit: $limit, offset: $offset) {
    id: uuid
    create_date
    reviewer_id
    reviewee_id
    reference_id
    reference_type
    comments
    rating
  }
}

mutation UpdateReviewById($id: uuid = "", $review: dctor_review_set_input = {}) {
  review: update_dctor_review_by_pk(pk_columns: {uuid: $id}, _set: $review) {
    uuid
  }
}

query MyQuery($where: treatment_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  findTreatments(where: $where, limit: $limit, offset: $offset) {
    category {
        id: uuid
        name
    }
    uuid
