    cpt_code
  }
}

mutation CompleteAppointment($id:uuid!) {
  appointment: updateEventById(pk_columns: {uuid: $id}, _set: {status: "completed"}) {
    condition
    dtend
    dtstart
    notes
    status
  }
}

mutation CancelAppointment($id:uuid!) {
  appointment: updateEventById(pk_columns: {uuid: $id}, _set: {status: "cancelled"}) {
    condition
    dtend
    dtstart
    notes
    status
  }
}

mutation UpdateEventById($id: uuid!, $appointment: event_set_input) {
