    }
  }
}

query ListInsuranceQuery($where: insurance_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  insurance: findInsurance(where: $where, limit: $limit, offset: $offset) {
    id: uuid
    emirates
    name
  }
}

query SearchQuery($where: user_bool_exp = {owner: {_eq: "dctor"}}, $limit: Int = null, $offset: Int = null) {
  users: findUsers(limit: $limit, offset: $offset, where: $where) {
    id
    name
  }
}

mutation createEvent($appointment: event_insert_input!) {
  appointment: createEvent(object: $appointment) {
    id: uuid
    condition
    dtend
    dtstart
    status
    attendees {
      attendee_id
    }
  }
}

mutation UpdateUserById($id: uuid, $user: user_set_input = {}, $new_insurance: [dctor_insurance_relation_insert_input!]! = [], $removed_insurance: [uuid!] = []) {
  user: updateUser(where: {id: {_eq: $id}, owner: {_eq: "dctor"}}, _set: $user) {
    returning {
      id
      first_name
      last_name
    }
  }
  added_insurance: insert_dctor_insurance_relation(objects: $new_insurance) {
    returning {
      insurance_id
    }
  }
  removed_insurance: delete_dctor_insurance_relation(where: {owner_id: {_eq: $id}, owner_type: {_in: ["admin", "clinic_admin", "doctor", "patient"]}, insurance_id: {_in: $removed_insurance}}) {
      returning {
          insurance_id
      }
  }
}

query dctor_facility($where: dctor_facility_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  facilities: dctor_facility(where: $where, limit: $limit, offset: $offset) {
    id: uuid
    bio
    email
    name
    phone
  }
}

mutation RescheduleAppointment($id:uuid!, $appointment: event_set_input) {
  appointment: updateEventById(pk_columns: {uuid: $id}, _set: $appointment) {
    condition
    dtend
    dtstart
    notes
    status
  }
}

query UserPhotosQuery($id: uuid!, $where: dctor_resource_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  photos: dctor_resource(where: {_and: [{owner_id: {_eq: $id}, owner_type: {_in: ["clinic_admin", "doctor", "patient"]}}, $where]}, offset: $offset, limit: $limit) {
    id: uuid
    url
  }
  total: dctor_resource_aggregate(where: {_and: [{owner_id: {_eq: $id}, owner_type: {_in: ["clinic_admin", "doctor", "patient"]}}, $where]}) {
    aggregate {
      count
    }
  }
}

query SearchQuery($where: dctor_search_index_bool_exp = {}, $limit: Int = null, $offset: Int = null, $is_anonymous: Boolean = true) {
  search_results: dctor_search_index(where: $where, limit: $limit, offset: $offset) {
    source_id
    source_type
    name
    addresses {
      address_line
      latitude
      longitude
    }
    availability {
      rule
      time_start
      time_end
      weekday
    }
    insurance_list {
      insurance {
        id: uuid
        name
        emirates
      }
    }
    treatments {
      id: treatment_id
      treatment {
        name
        cpt_code
      }
      currency
      price
    }
    user {
      phone @skip(if: $is_anonymous)
      health_facilities: left_relationships(where: {relationship_type: {_eq: "doctor_is_affiliated_to_clinic"}}) {
        facility: related_entity_as_facility {
          id: uuid
          name
          attributes: search_index {
            addresses {
              address_line
              latitude
              longitude
            }
          }
        }
        availability {
          weekday
          time_start
          time_end
          rule
        }
        insurance_list {
          insurance {
            id: uuid
            name
            emirates
          }
        }
        treatments {
          id: treatment_id
          treatment {
            name
            cpt_code
          }
          currency
          price
        }
      }
      reviews_received_stats: reviews_received_aggregate(where: {reviewee_type:{_in:["clinic_admin", "doctor", "patient"]}}) {
        aggregate {
          count
          avg {
            rating
          }
        }
      }
    }
    facility {
      name
      doctors: user_relationships(where: {relationship_type: {_eq: "doctor_is_affiliated_to_clinic"}}) {
        doctor: left_user {
          id
          name
        }
      }
      reviews_received_stats: reviews_received_aggregate(where: {reviewee_type:{_in:["clinic"]}}) {
        aggregate {
          count
          avg {
            rating
          }
        }
      }
    }
  }
  total: dctor_search_index_aggregate(where: $where) {
    aggregate {
      count
    }
  }
}

mutation RegisterEntityMutation($user: user_insert_input!, $permissions:  [iam_dctor_adapter_insert_input!]! = [], $password: IAMSetPassword! = {}) {
  user: registerUser(object: $user) {
        id
        health_facilities: left_relationships(where: {relationship_type: {_in: ["doctor_is_affiliated_to_clinic", "clinic_admin_manages_clinic"]}}) {
            facility: related_entity_as_facility {
              id: uuid
            }
        }
  }
  permissions: insert_iam_dctor_adapter(objects: $permissions) {
    affected_rows
  }
  password: iamSetPassword(data: $password) {
    status
  }
}

