query UserReviewsQuery($id: uuid!, $where: dctor_review_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  reviews: dctor_review(limit: $limit, offset: $offset, where: {_and: [{reviewee_id: {_eq: $id}}, {reviewee_type: {_in: ["clinic_admin", "doctor", "patient"]}}, $where]}) {
    id: uuid
    reviewer_id
    reviewee_id
    create_date
    rating
    reference_id
    reference_type
    comments
  }
  total:dctor_review_aggregate(where: {_and: [{reviewee_id: {_eq: $id}}, {reviewee_type: {_in: ["clinic_admin", "doctor", "patient"]}}, $where]}) {
    aggregate {
      count
    }
  }
}

query GetUserByIdQuery($id: String!, $dtstart: timestamp = null, $dtend: timestamp = null) {
  user: findUserById(username: $id, owner: "dctor") {
    id
    name
    avatar
    bio
    first_name
    last_name
    birthday
    gender
    phone
    email
    properties
    tag
    health_facilities: left_relationships(where: {relationship_type: {_in:[ "doctor_is_affiliated_to_clinic", "clinic_admin_manages_clinic"]}}) {
      facility: related_entity_as_facility {
        id: uuid
        name
        attributes: search_index {
          addresses {
            address_line
            latitude
            longitude
          }
        }
      }
      availability {
        weekday
        time_start
        time_end
        rule
      }
      insurance_list {
        insurance {
          id: uuid
          name
          emirates
        }
      }
      treatments {
        id: treatment_id
        treatment {
          name
          cpt_code
        }
        currency
        price
      }
    }
    insurance_list(where: {owner_type: {_in: ["admin", "clinic_admin", "doctor", "patient"]}}) {
			insurance {
        id: uuid
        name
      }
    }
  }
  calendar: iam_user_calendar(args: {dtstart: $dtstart, dtend: $dtend, user_id: $id}) {
    dtstart
    dtend
    is_available
    clinic_id
  }
  reviews_received_count: reviews_received_count(args: {user_id: $id}) {
    rating
    count
  }
}

query UserAppointmentsQuery($id: uuid!, $filter: event_bool_exp = {}, $limit: Int = null, $offset: Int = null, $order_by: [event_order_by!] = {}) {
  appointments: findEvents(limit: $limit, offset: $offset, where: {_and: [{attendees: {attendee_id: {_eq: $id}}}, $filter]}, order_by: $order_by) {
    id: uuid
    dtstart
    dtend
    notes
    status
    condition
    clinic_id
    attendees {
      id: uuid
      status
      attendee_id
    }
    doctor: attendees(where: {attendee: {tag: {_like: "%role_doctor%"}}}) {
      attendee_id
      status
      id: uuid
    }
    patient: attendees(where: {attendee: {tag: {_like: "%role_patient%"}}}) {
      attendee_id
      status
      id: uuid
    }
    referenced_reviews {
      rating
      comments
    }
  }
  total: event_aggregate(where: {_and: [{attendees: {attendee_id: {_eq: $id}}}, $filter]}) {
    aggregate {
      count
    }
  }
}

query ListTreatmentCategoriesQuery($where: dctor_treatment_category_bool_exp = {}, $limit: Int = null, $offset: Int = null, , $sub_limit: Int = null, $sub_offset: Int = null) {
  treatment_categories: dctor_treatment_category(where: {_and: [{parent_id: {_is_null: true}}, $where]}, limit: $limit, offset: $offset) {
    id: uuid
    name
    description
    icon_url
    parent {
      id: uuid
      name
    }
    sub_categories(limit: $sub_limit, offset: $sub_offset) {
      id: uuid
      name
      description
      icon_url
      attributes
    }
  }
}

query ListIamUserLinksQuery($id: uuid, $where: iam_user_link_bool_exp = {}, $limit: Int = null, $offset: Int = null) {
  links: iam_user_link(where: {_and: [{owner_id: {_eq: $id}}, $where]}, limit: $limit, offset: $offset) {
    id: uuid
    reference_id
    reference_type
  }
}

mutation AddIamUserLink($link: iam_user_link_insert_input!) {
  link: insert_iam_user_link_one(object: $link) {
    id: uuid
  }
}

mutation DeleteIAMUserLink($id: uuid = null, $where: iam_user_link_bool_exp!) {
  link: delete_iam_user_link(where: {_and: [{owner_id: {_eq: $id}}, $where]}) {
    returning {
      id: uuid
    }
  }
}
